import type { ClasseInfo } from './classes'

// ─── Classes de prestige D&D 3.5 ─────────────────────────────────────────────
// Extraites des suppléments : Codex Divin (CD), Codex Profane (CP),
// Les Maîtres de la Nature (MN), Manuel des Joueurs de Faerûn (MJF).
// Une classe de prestige se superpose à une classe de base (multi-classes).
// La mention de source figure à la fin de chaque résumé.

export interface ClassePrestigeInfo extends ClasseInfo {
  prestige: true
  source: string        // livre d'origine (mini note)
  conditions: string    // conditions d'accès résumées
  niveauxMax: number    // nombre de niveaux de la classe (5 ou 10 en général)
  // Progression de lancement de sorts : la classe ajoute ses niveaux au niveau
  // de lanceur d'une classe de base existante (« +1 niveau de lanceur »)
  // 'complete' = chaque niveau ; 'demi' = un niveau sur deux ; 'partielle' = selon niveauxAvecSorts
  progressionSorts?: 'complete' | 'demi' | 'partielle'
  niveauxAvecSorts?: number[]  // pour 'partielle' : niveaux de classe qui accordent +1 niveau de lanceur
  typeLanceur?: 'arcane' | 'divin' | 'les-deux'
  resume: string        // pouvoirs clés de la classe
}

