export function getPrestigeInfo(nom: string): ClassePrestigeInfo | undefined {
  return PRESTIGE_CLASSES.find(c => c.nom === nom)
}

// Niveau de lanceur effectif d'une classe de base, en comptant les classes de
// prestige à progression de sorts (« +1 niveau de lanceur existant »).
// Le bonus s'applique à la classe de base la plus élevée du type correspondant.
export function getNiveauLanceurEffectif(
  nomClasse: string,
  classesDuPerso: { classe: string; niveau: number }[]
): number {
  const propre = classesDuPerso.find(c => c.classe === nomClasse)?.niveau ?? 0
  if (propre === 0) return 0
  const type = CLASSES_ARCANES.includes(nomClasse) ? 'arcane'
    : CLASSES_DIVINES.includes(nomClasse) ? 'divin' : null
  if (!type) return propre
  const listeType = type === 'arcane' ? CLASSES_ARCANES : CLASSES_DIVINES
  const memesType = classesDuPerso.filter(c => listeType.includes(c.classe))
  const plusHaute = memesType.reduce((best, c) => c.niveau > best.niveau ? c : best, memesType[0])
  if (!plusHaute || plusHaute.classe !== nomClasse) return propre
  let bonus = 0
  for (const c of classesDuPerso) {
    const p = getPrestigeInfo(c.classe)
    if (!p?.progressionSorts) continue
    if (p.typeLanceur === 'les-deux' || p.typeLanceur === type) {
      bonus += p.progressionSorts === 'complete' ? c.niveau
        : p.progressionSorts === 'partielle' ? (p.niveauxAvecSorts ?? []).filter(n => n <= c.niveau).length
        : Math.floor(c.niveau / 2)
    }
  }
  return propre + bonus
}
